1→import { useEffect, useRef } from 'react'
2→import * as THREE from 'three'
3→
4→export default function HeroScene3D() {
5→  const mountRef = useRef(null)
6→
7→  useEffect(() => {
8→    const container = mountRef.current
9→    if (!container) return
10→
11→    // Respect reduced motion
12→    const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches
13→    const isMobile = window.innerWidth < 768
14→
15→    // Scene setup
16→    const scene = new THREE.Scene()
17→    const W = container.clientWidth
18→    const H = container.clientHeight
19→
20→    const camera = new THREE.PerspectiveCamera(55, W / H, 0.1, 100)
21→    camera.position.z = 7
22→    camera.position.x = 1.2
23→
24→    const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: !isMobile })
25→    renderer.setSize(W, H)
26→    renderer.setPixelRatio(Math.min(window.devicePixelRatio, isMobile ? 1 : 2))
27→    renderer.setClearColor(0x000000, 0)
28→    container.appendChild(renderer.domElement)
29→
30→    // Colors matching portfolio palette
31→    const C1 = new THREE.Color('#38bdf8') // sky
32→    const C2 = new THREE.Color('#a78bfa') // violet
33→    const C3 = new THREE.Color('#f472b6') // pink
34→    const C4 = new THREE.Color('#34d399') // emerald
35→
36→    // ── Main TorusKnot ──
37→    const torusGeo = new THREE.TorusKnotGeometry(1.0, 0.3, isMobile ? 64 : 128, isMobile ? 8 : 24)
38→    const torusMat = new THREE.MeshBasicMaterial({
39→      color: C1,
40→      wireframe: true,
41→      transparent: true,
42→      opacity: 0.1,
43→    })
44→    const torusKnot = new THREE.Mesh(torusGeo, torusMat)
45→    scene.add(torusKnot)
46→
47→    // Inner glow mesh (solid, very transparent)
48→    const glowMat = new THREE.MeshBasicMaterial({
49→      color: C2,
50→      transparent: true,
51→      opacity: 0.02,
52→      side: THREE.DoubleSide,
53→    })
54→    const glowMesh = new THREE.Mesh(torusGeo, glowMat)
55→    scene.add(glowMesh)
56→
57→    // ── Orbiting Icosahedrons ──
58→    const orbiters = []
59→    const orbiterCount = isMobile ? 3 : 6
60→    const orbiterColors = [C1, C2, C3, C4, C1, C3]
61→    for (let i = 0; i < orbiterCount; i++) {
62→      const size = 0.08 + Math.random() * 0.12
63→      const geo = new THREE.IcosahedronGeometry(size, 0)
64→      const mat = new THREE.MeshBasicMaterial({
65→        color: orbiterColors[i % orbiterColors.length],
66→        wireframe: true,
67→        transparent: true,
68→        opacity: 0.25,
69→      })
70→      const mesh = new THREE.Mesh(geo, mat)
71→
72→      // Orbit parameters
73→      const orbit = {
74→        mesh,
75→        radius: 2.2 + Math.random() * 1.2,
76→        speed: 0.3 + Math.random() * 0.5,
77→        phase: (Math.PI * 2 * i) / orbiterCount + Math.random() * 0.5,
78→        tilt: Math.random() * Math.PI * 0.5,
79→        rotSpeed: 0.5 + Math.random() * 1.5,
80→      }
81→      orbiters.push(orbit)
82→      scene.add(mesh)
83→    }
84→
85→    // ── Floating particles ──
86→    const particleCount = isMobile ? 30 : 80
87→    const particleGeo = new THREE.BufferGeometry()
88→    const particlePositions = new Float32Array(particleCount * 3)
89→    const particleSizes = new Float32Array(particleCount)
90→    for (let i = 0; i < particleCount; i++) {
91→      particlePositions[i * 3] = (Math.random() - 0.5) * 10
92→      particlePositions[i * 3 + 1] = (Math.random() - 0.5) * 10
93→      particlePositions[i * 3 + 2] = (Math.random() - 0.5) * 6
94→      particleSizes[i] = Math.random() * 3 + 1
95→    }
96→    particleGeo.setAttribute('position', new THREE.BufferAttribute(particlePositions, 3))
97→    particleGeo.setAttribute('size', new THREE.BufferAttribute(particleSizes, 1))
98→    const particleMat = new THREE.PointsMaterial({
99→      color: C1,
100→      size: 0.03,
101→      transparent: true,
102→      opacity: 0.4,
103→      sizeAttenuation: true,
104→    })
105→    const particles = new THREE.Points(particleGeo, particleMat)
106→    scene.add(particles)
107→
108→    // ── Mouse tracking ──
109→    const mouse = { x: 0, y: 0, targetX: 0, targetY: 0 }
110→    const onMouseMove = (e) => {
111→      mouse.targetX = (e.clientX / window.innerWidth) * 2 - 1
112→      mouse.targetY = -(e.clientY / window.innerHeight) * 2 + 1
113→    }
114→    window.addEventListener('mousemove', onMouseMove)
115→
116→    // ── Animation ──
117→    const clock = new THREE.Clock()
118→    let animId
119→
120→    function animate() {
121→      animId = requestAnimationFrame(animate)
122→      const t = clock.getElapsedTime()
123→      const speed = prefersReduced ? 0.15 : 1
124→
125→      // Smooth mouse interpolation
126→      mouse.x += (mouse.targetX - mouse.x) * 0.04
127→      mouse.y += (mouse.targetY - mouse.y) * 0.04
128→
129→      // Main torusKnot rotation + mouse tilt
130→      torusKnot.rotation.x = t * 0.12 * speed + mouse.y * 0.3
131→      torusKnot.rotation.y = t * 0.18 * speed + mouse.x * 0.3
132→      torusKnot.rotation.z = t * 0.06 * speed
133→
134→      // Pulse opacity
135→      torusMat.opacity = 0.08 + Math.sin(t * 0.8) * 0.04
136→      glowMat.opacity = 0.015 + Math.sin(t * 0.5) * 0.01
137→
138→      // Glow mesh follows with slight lag
139→      glowMesh.rotation.copy(torusKnot.rotation)
140→      glowMesh.rotation.x += 0.1
141→      glowMesh.rotation.y += 0.15
142→
143→      // Orbiting icosahedrons
144→      orbiters.forEach((o) => {
145→        const angle = t * o.speed * speed + o.phase
146→        o.mesh.position.x = Math.cos(angle) * o.radius
147→        o.mesh.position.y = Math.sin(angle) * o.radius * Math.cos(o.tilt)
148→        o.mesh.position.z = Math.sin(angle) * o.radius * Math.sin(o.tilt) * 0.5
149→        o.mesh.rotation.x = t * o.rotSpeed * speed
150→        o.mesh.rotation.y = t * o.rotSpeed * 0.7 * speed
151→      })
152→
153→      // Particles gentle drift
154→      const posArr = particles.geometry.attributes.position.array
155→      for (let i = 0; i < particleCount; i++) {
156→        posArr[i * 3 + 1] += Math.sin(t + i) * 0.001
157→        posArr[i * 3] += Math.cos(t * 0.5 + i * 0.3) * 0.0005
158→      }
159→      particles.geometry.attributes.position.needsUpdate = true
160→      particles.rotation.y = t * 0.02 * speed
161→
162→      // Color cycling
163→      const hue = (t * 0.05) % 1
164→      torusMat.color.setHSL(hue * 0.15 + 0.55, 0.8, 0.65)
165→
166→      renderer.render(scene, camera)
167→    }
168→    animate()
169→
170→    // ── Resize ──
171→    const onResize = () => {
172→      const w = container.clientWidth
173→      const h = container.clientHeight
174→      camera.aspect = w / h
175→      camera.updateProjectionMatrix()
176→      renderer.setSize(w, h)
177→    }
178→    window.addEventListener('resize', onResize)
179→
180→    return () => {
181→      cancelAnimationFrame(animId)
182→      window.removeEventListener('mousemove', onMouseMove)
183→      window.removeEventListener('resize', onResize)
184→      renderer.dispose()
185→      torusGeo.dispose()
186→      torusMat.dispose()
187→      glowMat.dispose()
188→      particleGeo.dispose()
189→      particleMat.dispose()
190→      orbiters.forEach((o) => {
191→        o.mesh.geometry.dispose()
192→        o.mesh.material.dispose()
193→      })
194→      if (container.contains(renderer.domElement)) {
195→        container.removeChild(renderer.domElement)
196→      }
197→    }
198→  }, [])
199→
200→  return (
201→    <div
202→      ref={mountRef}
203→      style={{
204→        position: 'absolute',
205→        inset: 0,
206→        zIndex: 0,
207→        pointerEvents: 'none',
208→        overflow: 'hidden',
209→      }}
210→    />
211→  )
212→}
EOF
